import{_ as a,o as r,c as o,a2 as e}from"./chunks/framework.DjxoKHTk.js";const c=JSON.parse('{"title":"正宗法國長棍麵包（Baguette）","description":"Fabrice主廚的專業法棍配方，T65麵粉、自解法、低溫冷藏發酵12小時，250°C帶蒸氣烤焙。","frontmatter":{"title":"正宗法國長棍麵包（Baguette）","description":"Fabrice主廚的專業法棍配方，T65麵粉、自解法、低溫冷藏發酵12小時，250°C帶蒸氣烤焙。"},"headers":[],"relativePath":"西式/法國長棍麵包.md","filePath":"西式/法國長棍麵包.md","lastUpdated":1781138667000}'),n={name:"西式/法國長棍麵包.md"};function l(s,t,i,d,h,g){return r(),o("div",null,[...t[0]||(t[0]=[e(`<h1 id="正宗法國長棍麵包-baguette" tabindex="-1">正宗法國長棍麵包（Baguette） <a class="header-anchor" href="#正宗法國長棍麵包-baguette" aria-label="Permalink to &quot;正宗法國長棍麵包（Baguette）&quot;">​</a></h1><p><strong>來源：</strong> <a href="https://youtu.be/XTY9IUJhaHA" target="_blank" rel="noreferrer">YouTube - Boulangerie Pas à pas</a><strong>分享日期：</strong> 2026/06/08 <strong>主廚：</strong> Fabrice（15歲開始做法國麵包，Boulangerie Pas à pas 頻道主）</p><hr><h2 id="📝-配方-可做-3-條" tabindex="-1">📝 配方（可做 3 條） <a class="header-anchor" href="#📝-配方-可做-3-條" aria-label="Permalink to &quot;📝 配方（可做 3 條）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>材料</th><th>用量</th><th>備註</th></tr></thead><tbody><tr><td>🌾 高筋麵粉 T65</td><td><strong>500 g</strong></td><td>無添加物</td></tr><tr><td>🧂 鹽</td><td><strong>9 g</strong></td><td></td></tr><tr><td>🧫 新鮮酵母</td><td><strong>4 g</strong></td><td>或乾酵母 <strong>2 g</strong></td></tr><tr><td>💧 水</td><td><strong>330 g</strong></td><td>溫度需計算（見下方）</td></tr><tr><td>🫘 天然酵種</td><td><strong>50 g</strong></td><td>選擇性，主廚用蘋果+蜂蜜自養6年</td></tr></tbody></table><hr><h2 id="⚙️-關鍵技巧" tabindex="-1">⚙️ 關鍵技巧 <a class="header-anchor" href="#⚙️-關鍵技巧" aria-label="Permalink to &quot;⚙️ 關鍵技巧&quot;">​</a></h2><h3 id="_1️⃣-水溫計算-—-基礎溫度法" tabindex="-1">1️⃣ 水溫計算 — 基礎溫度法 <a class="header-anchor" href="#_1️⃣-水溫計算-—-基礎溫度法" aria-label="Permalink to &quot;1️⃣ 水溫計算 — 基礎溫度法&quot;">​</a></h3><blockquote><p><strong>目標麵團溫度：23~26°C</strong> 公式：<strong>基礎溫度 − 室溫 − 麵粉溫度 = 水溫</strong></p></blockquote><p><strong>範例：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>基礎溫度 65°C</span></span>
<span class="line"><span>− 室溫 26°C</span></span>
<span class="line"><span>− 麵粉溫度 27°C</span></span>
<span class="line"><span>= 水溫 12°C ❄️</span></span></code></pre></div><h3 id="_2️⃣-自解法-autolyse-—-⏱-45分鐘" tabindex="-1">2️⃣ 自解法（Autolyse）— ⏱ 45分鐘 <a class="header-anchor" href="#_2️⃣-自解法-autolyse-—-⏱-45分鐘" aria-label="Permalink to &quot;2️⃣ 自解法（Autolyse）— ⏱ 45分鐘&quot;">​</a></h3><ul><li>水 + 麵粉，鉤狀頭慢速攪 <strong>3 分鐘</strong></li><li>保鮮膜蓋住，<strong>室溫靜置 45 分鐘</strong></li><li>目的：麵粉太強時改善延展性</li></ul><h3 id="_3️⃣-攪拌" tabindex="-1">3️⃣ 攪拌 <a class="header-anchor" href="#_3️⃣-攪拌" aria-label="Permalink to &quot;3️⃣ 攪拌&quot;">​</a></h3><ul><li>加入鹽、酵母、酵種</li><li><strong>低速8分鐘 + 中速2分鐘</strong></li><li>太乾可加少量水</li><li>⚡ <strong>窗玻璃測試（Window pane test）</strong>：確認麵筋網絡形成</li></ul><h3 id="_4️⃣-基礎發酵-pointage-—-⏱-1小時室溫" tabindex="-1">4️⃣ 基礎發酵（Pointage）— ⏱ 1小時室溫 <a class="header-anchor" href="#_4️⃣-基礎發酵-pointage-—-⏱-1小時室溫" aria-label="Permalink to &quot;4️⃣ 基礎發酵（Pointage）— ⏱ 1小時室溫&quot;">​</a></h3><ul><li>放入容器，做一次<strong>折疊（stretch &amp; fold）</strong></li><li>然後放入冰箱 <strong>4°C，冷藏12小時</strong> ❄️</li><li>目的：增加風味與保存性</li></ul><h3 id="_5️⃣-隔日步驟" tabindex="-1">5️⃣ 隔日步驟 <a class="header-anchor" href="#_5️⃣-隔日步驟" aria-label="Permalink to &quot;5️⃣ 隔日步驟&quot;">​</a></h3><ol><li>取出麵團回溫至 <strong>17°C</strong></li><li>分割 <strong>每份 300 g</strong></li><li>預整形成 batard（橢圓形）</li><li>撒薄粉，<strong>靜置 15 分鐘</strong>（蓋住）</li><li><strong>整形</strong>成棍形，接縫朝上放發酵布（couche）上</li><li>撒粉，輕拍排掉發酵氣泡</li><li>接縫朝下放回發酵布</li></ol><h3 id="_6️⃣-最後發酵-second-proof-—-⏱-45-分鐘室溫" tabindex="-1">6️⃣ 最後發酵（Second proof）— ⏱ 45 分鐘室溫 <a class="header-anchor" href="#_6️⃣-最後發酵-second-proof-—-⏱-45-分鐘室溫" aria-label="Permalink to &quot;6️⃣ 最後發酵（Second proof）— ⏱ 45 分鐘室溫&quot;">​</a></h3><ul><li>記得蓋住麵團</li></ul><h3 id="_7️⃣-割線-scoring" tabindex="-1">7️⃣ 割線（Scoring） <a class="header-anchor" href="#_7️⃣-割線-scoring" aria-label="Permalink to &quot;7️⃣ 割線（Scoring）&quot;">​</a></h3><ul><li>預熱烤箱 <strong>250°C</strong>（可放披薩石板）</li><li>用<strong>刮鬍刀片</strong>（非廚房刀）</li><li><strong>30公分的長棍割3刀</strong></li><li>撒上白麵粉裝飾</li></ul><h3 id="_8️⃣-烤焙" tabindex="-1">8️⃣ 烤焙 <a class="header-anchor" href="#_8️⃣-烤焙" aria-label="Permalink to &quot;8️⃣ 烤焙&quot;">​</a></h3><table tabindex="0"><thead><tr><th>步驟</th><th>時間</th><th>溫度</th></tr></thead><tbody><tr><td>🔥 帶蒸氣烤</td><td><strong>15 分鐘</strong></td><td>250°C</td></tr><tr><td>🌬️ 釋放蒸氣，續烤</td><td><strong>3~4 分鐘</strong></td><td>250°C</td></tr></tbody></table><p><strong>自製造蒸氣：</strong></p><ol><li>燒一壺熱水</li><li>打開烤箱門</li><li>麵團放進石板</li><li>底部烤盤倒入熱水 → <strong>快速關門</strong></li></ol><blockquote><p>💡 蒸氣是長棍漂亮色澤的關鍵！</p></blockquote><h3 id="_9️⃣-冷卻" tabindex="-1">9️⃣ 冷卻 <a class="header-anchor" href="#_9️⃣-冷卻" aria-label="Permalink to &quot;9️⃣ 冷卻&quot;">​</a></h3><ul><li>置於網架<strong>徹底放涼</strong></li></ul><hr><h2 id="🎯-主廚秘訣總整理" tabindex="-1">🎯 主廚秘訣總整理 <a class="header-anchor" href="#🎯-主廚秘訣總整理" aria-label="Permalink to &quot;🎯 主廚秘訣總整理&quot;">​</a></h2><table tabindex="0"><thead><tr><th>秘訣</th><th>說明</th></tr></thead><tbody><tr><td>🌡️ <strong>控溫</strong></td><td>水溫/室溫/麵粉溫度都影響發酵</td></tr><tr><td>🧪 <strong>窗玻璃測試</strong></td><td>確認麵筋是否到位</td></tr><tr><td>🧊 <strong>低溫長時間發酵</strong></td><td>12小時冷藏，風味更佳</td></tr><tr><td>💨 <strong>蒸氣</strong></td><td>麵包上色與外皮酥脆的關鍵</td></tr><tr><td>🧑‍🍳 <strong>工作檯保持乾淨</strong></td><td>隨時用刮板清潔，養成好習慣</td></tr></tbody></table><hr><h2 id="🥖-成功長棍的樣貌" tabindex="-1">🥖 成功長棍的樣貌 <a class="header-anchor" href="#🥖-成功長棍的樣貌" aria-label="Permalink to &quot;🥖 成功長棍的樣貌&quot;">​</a></h2><ul><li>外皮：⚡ <strong>酥脆聲</strong>（crunchy sound）</li><li>內部：🍯 <strong>蜂巢狀氣孔</strong>（honey comb structure）</li><li>香氣：天然發酵的麥香</li></ul><hr><p><em>由 Hermes 於 2026/06/08 整理</em></p>`,38)])])}const b=a(n,[["render",l]]);export{c as __pageData,b as default};
